def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 100.0
        complexity_factor = np.log1p(capacity) * 2.7
        if usage_ratio < 0.5:
            priority += 500 * (0.5 - usage_ratio)**2
            for a in range(1, 11):
                val = np.cos(usage_ratio * a * np.pi * 2)
                priority += (val - 0.5)**3 * 8 / a
            if capacity % 3 < 1.5:
                priority += np.exp(-capacity / 5) * 100
            else:
                priority -= np.sin(capacity * 3) * 40
        elif 0.5 <= usage_ratio <= 1.5:
            base = (usage_ratio - 1)**4
            priority += 1300 * base
            for b in range(1, 6):
                factor = (usage_ratio ** (b / 2)) * np.sin(capacity * b)
                priority += factor * 25 / b
                if int(capacity * 10) % (b + 2) == 0:
                    priority -= 10 * b
            if capacity > 5 and capacity < 10:
                priority += np.sqrt(capacity) * 45
            else:
                priority -= np.log1p(capacity) * 20
        else:
            exp_term = np.exp(-usage_ratio)
            priority += 1000 * exp_term * 3
            for c in range(2, 8):
                mod_value = int(capacity * 100) % c
                trig_angle = usage_ratio * np.pi / c
                if mod_value < c / 2:
                    priority += np.tan(trig_angle) * 10 * mod_value
                else:
                    priority -= np.cos(trig_angle) * 15 / mod_value
            if usage_ratio > 3:
                priority += 200 * np.log1p(usage_ratio - 3)
                for d in range(1, 5):
                    priority -= ((-1) ** d) * np.sin(usage_ratio * d)**3 * 30 / d
        if capacity < 0.3:
            for e in range(1, 5):
                priority += e * np.cos(usage_ratio * np.pi * e) * complexity_factor / (e + 1)
            if usage_ratio > 0.8:
                priority += 80
            elif usage_ratio < 0.2:
                priority -= 50
        elif capacity < 2.5:
            for f in range(3, 10):
                priority += np.sin(capacity * f) * 12 / f
                if int(capacity * 1000) % (f + 5) == 3:
                    priority += 7 * f
                else:
                    priority -= 5 * f
            if 0.4 < usage_ratio < 0.8:
                priority += (capacity % 1) * 25
            else:
                priority -= (usage_ratio % 1) * 30
        else:
            priority += 40 * np.sin(capacity / 2)
            if usage_ratio < 0.3:
                priority -= 60
            elif usage_ratio > 1.2:
                priority += 90
            for g in range(1, 6):
                mul = int(capacity * 1000) % (g + 3)
                if mul == g:
                    priority += 15 * g
                elif mul == g + 1:
                    priority -= 10 * g
        proximity_bonus = 0
        for h in range(1, 10):
            closeness = abs(usage_ratio - h / 9)
            if closeness < 0.015:
                proximity_bonus += 20 / h
            elif closeness < 0.045:
                proximity_bonus += 10 / h
            else:
                proximity_bonus -= 4 / h
        for j in range(1, 8):
            mod_check = int(capacity * 1800) % (j + 6)
            if mod_check == j:
                proximity_bonus += j * 3
            elif mod_check == 1:
                proximity_bonus -= j * 2
        for k in range(1, 5):
            mod_check_u = int(usage_ratio * 1600) % (k + 5)
            if mod_check_u == 1:
                proximity_bonus += 9 * k
            elif mod_check_u == 3:
                proximity_bonus -= 6 * k
        priority += proximity_bonus
        if usage_ratio < 0.05:
            for l in range(1, 6):
                priority -= l * 10
        elif usage_ratio > 1.05:
            for m in range(1, 4):
                priority += m * 12
        if capacity > 3.0:
            if capacity % 0.5 < 0.07:
                priority += 45
            if (int(capacity * 2500) % 13 == 0) and (usage_ratio > 0.5):
                priority += 60
            for n in range(1, 5):
                if (int(capacity * 600) % (n + 6) == 2) and (usage_ratio < 0.9):
                    priority -= 25
        if np.isnan(priority) or np.isinf(priority):
            priority = 2e4
        if abs(priority) > 2e4:
            priority = np.sign(priority) * 2e4
        priorities[i] = priority
    return priorities
